 28â†’/**
 29â†’ * JUnit 5 tests for HW04 update strategies and paint strategies.
 30â†’ * Tests are designed to run without a GUI by creating Ball objects
 31â†’ * directly and asserting on state changes.
 32â†’ */
 33â†’class PaintStrategyTest {
 34â†’
 35â†’    /** Simple IDimension mock returning fixed width and height. */
 36â†’    private IDimension mockDim(int w, int h) {
 37â†’        return new IDimension() {
 38â†’            public int getWidth() { return w; }
 39â†’            public int getHeight() { return h; }
 40â†’        };
 41â†’    }
 42â†’
 43â†’    /** Create a Graphics object backed by an off-screen BufferedImage. */
 44â†’    private Graphics getGraphics() {
 45â†’        return new BufferedImage(800, 600, BufferedImage.TYPE_INT_ARGB).createGraphics();
 46â†’    }
 47â†’
 48â†’    /** No-op IBallAlgo that does nothing on construction. */
 49â†’    private IBallAlgo noOpAlgo() {
 50â†’        return new IBallAlgo() {
 51â†’            public void caseDefault(IBall host) {
 52â†’                // no-op: do not install any strategies
 53â†’            }
 54â†’        };
 55â†’    }
 56â†’
 57â†’    /**
 58â†’     * Create a Ball with sane defaults for testing.
 59â†’     * The no-op IBallAlgo avoids GUI dependencies during construction.
 60â†’     * Canvas is null since we do not need a real container for these tests.
 61â†’     */
 62â†’    private Ball makeBall(Point location, Point velocity, Color color, int radius) {
 63â†’        return new Ball(location, velocity, color, radius, mockDim(800, 600), null, noOpAlgo());
 64â†’    }
 65â†’
 66â†’    // ---------------------------------------------------------------
 67â†’    // StraightStrategy tests
 68â†’    // ---------------------------------------------------------------
 69â†’
 70â†’    @Test
 71â†’    void testStraightStrategyNoOp() {
 72â†’        Ball ball = makeBall(new Point(100, 100), new Point(5, 3), Color.RED, 10);
 73â†’        ball.setUpdateStrategy(new StraightStrategy());
 74â†’        IDispatcher<IBallCmd> disp = new SequentialDispatcher<>();
 75â†’        Point velBefore = new Point(ball.getVelocity());
 76â†’        Color colorBefore = ball.getColor();
 77â†’        int radiusBefore = ball.getRadius();
 78â†’
 79â†’        ball.updateState(disp);
 80â†’
 81â†’        assertEquals(velBefore, ball.getVelocity(), "StraightStrategy should not change velocity");
 82â†’        assertEquals(colorBefore, ball.getColor(), "StraightStrategy should not change color");
 83â†’        assertEquals(radiusBefore, ball.getRadius(), "StraightStrategy should not change radius");
 84â†’    }
 85â†’
