 88â†’    // ---------------------------------------------------------------
 89â†’
 90â†’    @Test
 91â†’    void testGravityStrategyAddsToYVelocity() {
 92â†’        Ball ball = makeBall(new Point(100, 100), new Point(5, 0), Color.RED, 10);
 93â†’        ball.setUpdateStrategy(new GravityStrategy());
 94â†’        IDispatcher<IBallCmd> disp = new SequentialDispatcher<>();
 95â†’
 96â†’        ball.updateState(disp);
 97â†’
 98â†’        assertEquals(5, ball.getVelocity().x, "GravityStrategy should not change x velocity");
 99â†’        assertEquals(1, ball.getVelocity().y, "GravityStrategy should add 1 to y velocity");
100â†’    }
101â†’
102â†’    @Test
103â†’    void testGravityStrategyCumulative() {
104â†’        Ball ball = makeBall(new Point(100, 100), new Point(0, 0), Color.RED, 10);
105â†’        ball.setUpdateStrategy(new GravityStrategy());
106â†’        IDispatcher<IBallCmd> disp = new SequentialDispatcher<>();
107â†’
108â†’        for (int i = 0; i < 5; i++) {
109â†’            ball.updateState(disp);
110â†’        }
111â†’
112â†’        assertEquals(5, ball.getVelocity().y, "GravityStrategy should add 1 to y velocity each update");
113â†’    }
