117â†’    // ---------------------------------------------------------------
118â†’
119â†’    @Test
120â†’    void testColorStrategyChangesColor() {
121â†’        Ball ball = makeBall(new Point(100, 100), new Point(5, 3), Color.RED, 10);
122â†’        ball.setUpdateStrategy(new ColorStrategy());
123â†’        IDispatcher<IBallCmd> disp = new SequentialDispatcher<>();
124â†’
125â†’        // Run multiple updates; random color should differ from RED at least once
126â†’        boolean colorChanged = false;
127â†’        for (int i = 0; i < 50; i++) {
