@Override
public void init(IBall thisBall) {
	if (image != null) {
		atImage = thisBall.getCanvas() != null
				? IATImage.FACTORY.apply(image, thisBall.getCanvas())
				: null;
		if (atImage != null) {
			scale = fill / Math.max(atImage.getWidth() / 2.0, atImage.getHeight() / 2.0);
			preAT.setToScale(scale, scale);
			preAT.translate(-atImage.getWidth() / 2.0, -atImage.getHeight() / 2.0);
		}
	}
}

@Override
public void paintXfrm(Graphics g, IBall thisBall, AffineTransform tf) {
	if (atImage != null) {
		tempAT.setTransform(tf);
		tempAT.concatenate(preAT);
		atImage.draw(g, tempAT);
	}
}

